func CreateEnrollmentAfterFirstTouch(d *sql.DB, opts EnrollOpts) (*Enrollment, *Task, error) {
    tx, err := d.Begin()
    if err != nil {
        return nil, nil, fmt.Errorf("beginning transaction: %w", err)
    }
    defer tx.Rollback()

    // Check inside transaction to prevent race condition
    var existingID string
    err = tx.QueryRow(`
        SELECT id FROM sequence_enrollments
        WHERE mailbox_id = ? AND lower(contact_email) = lower(?)
        AND status IN (?, ?)
        LIMIT 1`,
