package sequence

import (
	"database/sql"
	"fmt"
	"strings"
	"time"
)

func ListTasks(d *sql.DB, opts TaskListOptions) ([]Task, error) {
	if opts.Now.IsZero() {
		opts.Now = time.Now()
	}

	query := `
		SELECT
			t.id, t.enrollment_id, e.sequence_name, e.campaign_name, t.mailbox_id, m.email,
			t.contact_email, t.subject, t.thread_id, t.step_number, t.step_name,
			t.send_type, t.status, t.due_at, t.body, t.send_status, t.last_attempt_at, t.last_error, t.attempt_count
		FROM follow_up_tasks t
		JOIN sequence_enrollments e ON e.id = t.enrollment_id
		JOIN mailboxes m ON m.id = t.mailbox_id
		WHERE t.status = ? AND e.status = ?`
	args := []any{TaskStatusOpen, StatusActive}

	if !opts.IncludeFuture {
		query += " AND t.due_at <= ?"
		args = append(args, opts.Now.UTC().Format(time.RFC3339))
	}

	query += " ORDER BY t.due_at ASC"
	if opts.Limit > 0 {
		query += fmt.Sprintf(" LIMIT %d", opts.Limit)
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var tasks []Task
	for rows.Next() {
		var task Task
		if err := rows.Scan(
			&task.ID, &task.EnrollmentID, &task.SequenceName, &task.CampaignName, &task.MailboxID,
			&task.MailboxEmail, &task.ContactEmail, &task.Subject, &task.ThreadID,
			&task.StepNumber, &task.StepName, &task.SendType, &task.Status, &task.DueAt,
			&task.Body, &task.SendStatus, &task.LastAttemptAt, &task.LastError, &task.AttemptCount,
		); err != nil {
			return nil, err
		}
		task.DaysUntilDue = daysUntil(task.DueAt, opts.Now)
		tasks = append(tasks, task)
	}

	return tasks, rows.Err()
}

func ListDispatchTasks(d *sql.DB, now time.Time, limit int) ([]DispatchTask, error) {
	return ListDispatchTasksForTransport(d, DispatchOptions{
		Limit: limit,
		Now:   now,
	})
}

func ListDispatchTasksForTransport(d *sql.DB, opts DispatchOptions) ([]DispatchTask, error) {
	if opts.Now.IsZero() {
		opts.Now = time.Now()
	}

	tasks, err := ListTasks(d, TaskListOptions{
		IncludeFuture: false,
		Limit:         opts.Limit,
		Now:           opts.Now,
	})
	if err != nil {
		return nil, err
	}

	dispatch := make([]DispatchTask, 0, len(tasks))
	for _, task := range tasks {
		item := DispatchTask{Task: task, Ready: true}
		if suppression, suppressed, err := IsSuppressed(d, task.ContactEmail); err != nil {
			return nil, err
		} else if suppressed {
			item.Ready = false
			item.BlockedReason = fmt.Sprintf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
			dispatch = append(dispatch, item)
			continue
		}

		mailbox, err := ResolveTaskMailbox(d, task, opts.TransportEmail, opts.Now)
		if err != nil {
			item.Ready = false
			item.BlockedReason = err.Error()
			dispatch = append(dispatch, item)
			continue
		}
		item.SelectedMailboxID = mailbox.ID
		item.SelectedMailboxEmail = mailbox.Email
		item.TransportEmail = effectiveTransportEmail(*mailbox)
		item.RenderedSubject, item.RenderedBody, err = RenderTaskContent(d, task)
		if err != nil {
			return nil, err
		}
		dispatch = append(dispatch, item)
	}
	return dispatch, nil
}

