func SnoozeTask(d *sql.DB, taskID string, byDays int) (*Task, error) {
	if byDays <= 0 {
		byDays = 1
	}
	task, err := TaskByID(d, taskID)
	if err != nil {
		return nil, err
	}
	if task.Status != TaskStatusOpen {
		return nil, fmt.Errorf("task %s is %s", task.ID, task.Status)
	}

	dueAt, err := time.Parse(time.RFC3339, task.DueAt)
	if err != nil {
		return nil, fmt.Errorf("parsing due_at for task %s: %w", task.ID, err)
	}
	newDueAt := dueAt.AddDate(0, 0, byDays).UTC().Format(time.RFC3339)

	_, err = d.Exec(`
		UPDATE follow_up_tasks
		SET due_at = ?, updated_at = datetime('now')
		WHERE id = ?`,
		newDueAt, task.ID,
	)
	if err != nil {
		return nil, err
	}

