func RecordSend(d *sql.DB, mailboxID, sendType string, now time.Time) error {
	normalized := NormalizeSendType(sendType)
	// If the original type was not a recognized value and fell back to "manual", reject it.
	if normalized == SendTypeManual && sendType != SendTypeManual {
		return fmt.Errorf("unknown send type %q: expected one of first_touch, follow_up, reply, manual", sendType)
	}
	if normalized == SendTypeManual {
		return nil
	}
	sendType = normalized
	if now.IsZero() {
		now = time.Now()
	}

	_, err := d.Exec(`
		INSERT INTO mailbox_daily_usage (
			mailbox_id, usage_day, first_touches_sent, follow_ups_sent, replies_sent
		) VALUES (?, ?, 0, 0, 0)
		ON CONFLICT(mailbox_id, usage_day) DO NOTHING`,
		mailboxID, dayKey(now),
	)
	if err != nil {
		return err
	}

	column := usageColumn(sendType)
	// Validate the column name is one of the known safe values before interpolation
	switch column {
	case "first_touches_sent", "follow_ups_sent", "replies_sent":
		if err := validateIdentifier(column); err != nil {
			return fmt.Errorf("unsafe column name %q: %w", column, err)
		}
		if _, err := d.Exec(
			fmt.Sprintf(`UPDATE mailbox_daily_usage SET %s = %s + 1 WHERE mailbox_id = ? AND usage_day = ?`, column, column),
			mailboxID, dayKey(now),
		); err != nil {
			return err
		}
	case "":
		// No usage column for this send type (e.g. manual)
	default:
		return fmt.Errorf("unexpected usage column %q for send type %q", column, sendType)
	}

	if _, err := d.Exec(`
		INSERT INTO mailbox_send_events (id, mailbox_id, send_type, sent_at)
		VALUES (?, ?, ?, ?)`,
		newID("mse"), mailboxID, sendType, now.UTC().Format(time.RFC3339),
	); err != nil {
		return err
	}

	_, err = d.Exec(`UPDATE mailboxes SET last_used_at = ?, updated_at = datetime('now') WHERE id = ?`, now.UTC().Format(time.RFC3339), mailboxID)
