package sequence

import (
	"database/sql"
	"fmt"
	"strings"
	"time"
)

type execer interface {
	Exec(query string, args ...any) (sql.Result, error)
}

const (
	TaskSendStatusPending = "pending"
	TaskSendStatusSent    = "sent"
	TaskSendStatusFailed  = "failed"
)

type SendAttempt struct {
	ID           string `json:"id"`
	MailboxID    string `json:"mailbox_id"`
	MailboxEmail string `json:"mailbox_email"`
	EnrollmentID string `json:"enrollment_id"`
	TaskID       string `json:"task_id"`
	ContactEmail string `json:"contact_email"`
	SendType     string `json:"send_type"`
	Status       string `json:"status"`
	Subject      string `json:"subject"`
	Error        string `json:"error"`
	MessageID    string `json:"message_id"`
	ProviderID   string `json:"provider_id"`
	AttemptedAt  string `json:"attempted_at"`
}

type SequenceDraft struct {
	ID               string `json:"id"`
	EnrollmentID     string `json:"enrollment_id"`
	TaskID           string `json:"task_id"`
	StepNumber       int    `json:"step_number"`
	Subject          string `json:"subject"`
	Body             string `json:"body"`
	Channel          string `json:"channel"`
	Status           string `json:"status"`
	GeneratedBy      string `json:"generated_by"`
	GeneratedContext string `json:"generated_context"`
}

type SendAttemptOptions struct {
	MailboxID    string
	EnrollmentID string
	TaskID       string
	ContactEmail string
	SendType     string
	Status       string
	Subject      string
	Error        string
	MessageID    string
	ProviderID   string
	AttemptedAt  time.Time
}

func RecordSend(d *sql.DB, mailboxID, sendType string, now time.Time) error {
	normalized := NormalizeSendType(sendType)
	// If the original type was not a recognized value and fell back to "manual", reject it.
	if normalized == SendTypeManual && sendType != SendTypeManual {
		return fmt.Errorf("unknown send type %q: expected one of first_touch, follow_up, reply, manual", sendType)
	}
	if normalized == SendTypeManual {
		return nil
	}
	sendType = normalized
	if now.IsZero() {
		now = time.Now()
	}

	_, err := d.Exec(`
		INSERT INTO mailbox_daily_usage (
			mailbox_id, usage_day, first_touches_sent, follow_ups_sent, replies_sent
		) VALUES (?, ?, 0, 0, 0)
		ON CONFLICT(mailbox_id, usage_day) DO NOTHING`,
		mailboxID, dayKey(now),
	)
	if err != nil {
		return err
	}

	column := usageColumn(sendType)
	// Validate the column name is one of the known safe values before interpolation
	switch column {
	case "first_touches_sent", "follow_ups_sent", "replies_sent":
		if err := validateIdentifier(column); err != nil {
			return fmt.Errorf("unsafe column name %q: %w", column, err)
		}
		if _, err := d.Exec(
			fmt.Sprintf(`UPDATE mailbox_daily_usage SET %s = %s + 1 WHERE mailbox_id = ? AND usage_day = ?`, column, column),
			mailboxID, dayKey(now),
		); err != nil {
			return err
		}
	case "":
		// No usage column for this send type (e.g. manual)
	default:
		return fmt.Errorf("unexpected usage column %q for send type %q", column, sendType)
	}

	if _, err := d.Exec(`
		INSERT INTO mailbox_send_events (id, mailbox_id, send_type, sent_at)
		VALUES (?, ?, ?, ?)`,
		newID("mse"), mailboxID, sendType, now.UTC().Format(time.RFC3339),
	); err != nil {
		return err
	}

	_, err = d.Exec(`UPDATE mailboxes SET last_used_at = ?, updated_at = datetime('now') WHERE id = ?`, now.UTC().Format(time.RFC3339), mailboxID)
	return err
}

func LogSendAttempt(d *sql.DB, opts SendAttemptOptions) error {
	if opts.MailboxID == "" {
		return fmt.Errorf("mailbox ID is required")
	}
	if strings.TrimSpace(opts.ContactEmail) == "" {
		return fmt.Errorf("contact email is required")
	}
	if strings.TrimSpace(opts.Status) == "" {
		return fmt.Errorf("send attempt status is required")
	}
	if opts.AttemptedAt.IsZero() {
		opts.AttemptedAt = time.Now()
	}

	_, err := d.Exec(`
		INSERT INTO send_attempts (
			id, mailbox_id, enrollment_id, task_id, contact_email, send_type,
			status, subject, error, message_id, provider_id, attempted_at
		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		newID("send"), opts.MailboxID, opts.EnrollmentID, opts.TaskID, strings.ToLower(strings.TrimSpace(opts.ContactEmail)),
		NormalizeSendType(opts.SendType), opts.Status, opts.Subject, opts.Error, opts.MessageID, opts.ProviderID,
		opts.AttemptedAt.UTC().Format(time.RFC3339),
	)
	return err
}

func ListSendAttempts(d *sql.DB, limit int, status string) ([]SendAttempt, error) {
	query := `
		SELECT s.id, s.mailbox_id, m.email, s.enrollment_id, s.task_id, s.contact_email, s.send_type,
			s.status, s.subject, s.error, s.message_id, s.provider_id, s.attempted_at
		FROM send_attempts s
		JOIN mailboxes m ON m.id = s.mailbox_id`
	var args []any
	if status != "" {
		query += ` WHERE s.status = ?`
		args = append(args, status)
	}
	query += ` ORDER BY s.attempted_at DESC`
	if limit > 0 {
		query += " LIMIT ?"
		args = append(args, limit)
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var attempts []SendAttempt
	for rows.Next() {
		var item SendAttempt
		if err := rows.Scan(
			&item.ID, &item.MailboxID, &item.MailboxEmail, &item.EnrollmentID, &item.TaskID, &item.ContactEmail,
			&item.SendType, &item.Status, &item.Subject, &item.Error, &item.MessageID, &item.ProviderID, &item.AttemptedAt,
		); err != nil {
			return nil, err
		}
		attempts = append(attempts, item)
	}
	return attempts, rows.Err()
}

func UpdateTaskSendState(d *sql.DB, taskID, sendStatus, messageID, providerID, lastError string) error {
	sendStatus = strings.TrimSpace(sendStatus)
	if sendStatus == "" {
		sendStatus = TaskSendStatusPending
	}
	_, err := d.Exec(`
		UPDATE follow_up_tasks
		SET send_status = ?,
			unipile_message_id = CASE WHEN ? = '' THEN unipile_message_id ELSE ? END,
			provider_id = CASE WHEN ? = '' THEN provider_id ELSE ? END,
			last_error = CASE WHEN ? = '' THEN last_error ELSE ? END,
			updated_at = datetime('now')
		WHERE id = ?`,
		sendStatus,
		messageID, messageID,
		providerID, providerID,
		lastError, lastError,
		taskID,
	)
	return err
}

func UpsertDraftForTask(d execer, taskID, enrollmentID string, stepNumber int, subject, body, generatedBy, generatedContext string) error {
	if taskID == "" || enrollmentID == "" {
		return fmt.Errorf("task ID and enrollment ID are required")
	}
	_, err := d.Exec(`
		INSERT INTO sequence_drafts (
			id, enrollment_id, task_id, step_number, subject, body, channel, status, generated_by, generated_context
		) VALUES (?, ?, ?, ?, ?, ?, 'email', 'pending', ?, ?)
		ON CONFLICT(task_id) DO UPDATE SET
			subject = excluded.subject,
			body = excluded.body,
			generated_by = excluded.generated_by,
			generated_context = excluded.generated_context,
			status = CASE
				WHEN sequence_drafts.status = 'sent' THEN sequence_drafts.status
				ELSE excluded.status
			END,
			updated_at = datetime('now')`,
		newID("draft"), enrollmentID, taskID, stepNumber, subject, body, generatedBy, generatedContext,
	)
	return err
}

func DraftByTaskID(d *sql.DB, taskID string) (*SequenceDraft, error) {
	row := d.QueryRow(`
		SELECT id, enrollment_id, task_id, step_number, subject, body, channel, status, generated_by, generated_context
		FROM sequence_drafts
		WHERE task_id = ?`,
		taskID,
	)
	var draft SequenceDraft
	if err := row.Scan(
		&draft.ID, &draft.EnrollmentID, &draft.TaskID, &draft.StepNumber, &draft.Subject, &draft.Body,
		&draft.Channel, &draft.Status, &draft.GeneratedBy, &draft.GeneratedContext,
	); err != nil {
		if err == sql.ErrNoRows {
			return nil, fmt.Errorf("draft for task %q not found", taskID)
		}
		return nil, err
	}
	return &draft, nil
}

func UpdateDraftStatusByTaskID(d execer, taskID, status string) error {
	_, err := d.Exec(`UPDATE sequence_drafts SET status = ?, updated_at = datetime('now') WHERE task_id = ?`, status, taskID)
	return err
}

