		var count int
		if err := d.QueryRow("SELECT COUNT(*) FROM mailboxes").Scan(&count); err != nil {
			return nil, fmt.Errorf("checking mailbox count: %w", err)
		}
		if count >= MaxMailboxes {
			return nil, fmt.Errorf("mailbox limit reached (%d). Current plan supports up to %d sending accounts", count, MaxMailboxes)
		}
	}

	_, err := d.Exec(`
		INSERT INTO mailboxes (id, email, transport_email, provider, warmup_started_at)
		VALUES (?, ?, ?, ?, datetime('now'))
		ON CONFLICT(email) DO UPDATE SET
			provider = excluded.provider,
			transport_email = CASE
				WHEN mailboxes.transport_email = '' THEN excluded.transport_email
				ELSE mailboxes.transport_email
			END,
			warmup_started_at = CASE
				WHEN mailboxes.warmup_started_at = '' THEN excluded.warmup_started_at
				ELSE mailboxes.warmup_started_at
			END,
			updated_at = datetime('now')`,
		newID("mbx"), email, email, provider,
	)
	if err != nil {
		return nil, err
	}

	return mailboxByEmail(d, email)
}

func ListMailboxes(d *sql.DB, now time.Time) ([]MailboxStatus, error) {
	if now.IsZero() {
		now = time.Now()
	}

func sanitizeHeader(s string) string {
	r := strings.NewReplacer("\r", " ", "\n", " ")
	return r.Replace(s)
}

func buildRawMessage(from string, opts SendOptions) string {
	var b strings.Builder
	b.WriteString("From: " + from + "\r\n")
	b.WriteString("To: " + opts.To + "\r\n")
	if opts.Cc != "" {
		b.WriteString("Cc: " + opts.Cc + "\r\n")
	}
	b.WriteString("Subject: " + sanitizeHeader(opts.Subject) + "\r\n")
	b.WriteString("MIME-Version: 1.0\r\n")
	b.WriteString("Content-Type: text/plain; charset=\"UTF-8\"\r\n")
	b.WriteString("\r\n")
	b.WriteString(opts.Body)
	return b.String()
}

