	ByClass      map[string]int `json:"by_class"`
	DateRange    DateRange      `json:"date_range"`
	Unclassified int            `json:"unclassified"`
}

type DateRange struct {
	Earliest string `json:"earliest"`
	Latest   string `json:"latest"`
}

// WeeklyStats holds outbound activity for the current week (Monday to now).
type WeeklyStats struct {
	OutboundSent   int `json:"outbound_sent"`
	UniqueContacts int `json:"unique_contacts"`
}

func Stats(d *sql.DB) (*EmailStats, error) {
	stats := &EmailStats{ByClass: make(map[string]int)}

	if err := d.QueryRow("SELECT COUNT(*) FROM emails").Scan(&stats.Total); err != nil {
		return nil, fmt.Errorf("counting emails: %w", err)
	}

	rows, err := d.Query("SELECT class, COUNT(*) FROM emails GROUP BY class")
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	for rows.Next() {
		var class string
		var count int
		if err := rows.Scan(&class, &count); err != nil {
			return nil, fmt.Errorf("scanning class count: %w", err)
		}
		stats.ByClass[class] = count
		if class == "unclassified" {
			stats.Unclassified = count
		}
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterating class counts: %w", err)
	}

	var earliest, latest sql.NullString
	if err := d.QueryRow("SELECT MIN(date), MAX(date) FROM emails").Scan(&earliest, &latest); err != nil {
		return nil, fmt.Errorf("querying date range: %w", err)
	}
	stats.DateRange.Earliest = earliest.String
	stats.DateRange.Latest = latest.String

	return stats, nil
}

