	w := &WeeklyStats{}

	now := time.Now()
	weekday := int(now.Weekday())
	if weekday == 0 {
		weekday = 7 // Sunday = 7
	}
	monday := now.AddDate(0, 0, -(weekday - 1))
	mondayStr := monday.Format("2006-01-02")

	if err := d.QueryRow(
		"SELECT COUNT(*) FROM emails WHERE class = 'outbound' AND date >= ?",
