		"SELECT COUNT(DISTINCT to_emails) FROM emails WHERE class = 'outbound' AND date >= ?",
		mondayStr,
	).Scan(&w.UniqueContacts); err != nil {
		return nil, fmt.Errorf("counting unique contacts this week: %w", err)
	}

	return w, nil
}

