package email

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"sort"
	"strings"
)

type Context struct {
	TotalEmails    int              `json:"total_emails"`
	OutboundCount  int              `json:"outbound_count"`
	TopRecipients  []RecipientCount `json:"top_recipients"`
	TopDomains     []DomainCount    `json:"top_domains"`
	SendingPattern SendingPattern   `json:"sending_pattern"`
	CommonSubjects []string         `json:"common_subjects"`
}

type RecipientCount struct {
	Email string `json:"email"`
	Count int    `json:"count"`
}

type DomainCount struct {
	Domain string `json:"domain"`
	Count  int    `json:"count"`
}

type SendingPattern struct {
	MostActiveDay string  `json:"most_active_day"`
	AvgPerDay     float64 `json:"avg_per_day"`
	AvgPerWeek    float64 `json:"avg_per_week"`
}

func GenerateContext(d *sql.DB) (*Context, error) {
	ctx := &Context{}

	if err := d.QueryRow("SELECT COUNT(*) FROM emails").Scan(&ctx.TotalEmails); err != nil {
		return nil, fmt.Errorf("querying total emails: %w", err)
	}
	if err := d.QueryRow("SELECT COUNT(*) FROM emails WHERE class = 'outbound'").Scan(&ctx.OutboundCount); err != nil {
		return nil, fmt.Errorf("querying outbound count: %w", err)
	}

	// Parse to_emails JSON to get actual recipient counts and domain counts
	recipientCounts := make(map[string]int)
	domainCounts := make(map[string]int)

	rows, err := d.Query("SELECT to_emails FROM emails WHERE class = 'outbound'")
	if err != nil {
		return nil, fmt.Errorf("querying outbound to_emails: %w", err)
	}
	defer rows.Close()
	for rows.Next() {
		var toJSON string
		if err := rows.Scan(&toJSON); err != nil {
			return nil, fmt.Errorf("scanning to_emails row: %w", err)
		}
		var addrs []string
		if json.Unmarshal([]byte(toJSON), &addrs) == nil {
			for _, addr := range addrs {
				recipientCounts[addr]++
				if parts := strings.SplitN(addr, "@", 2); len(parts) == 2 {
					domainCounts[parts[1]]++
				}
			}
		}
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterating outbound to_emails rows: %w", err)
	}

	// Sort by count (top 10)
	ctx.TopRecipients = topN(recipientCounts, 10, func(k string, v int) RecipientCount {
		return RecipientCount{Email: k, Count: v}
	})
	ctx.TopDomains = topN(domainCounts, 10, func(k string, v int) DomainCount {
		return DomainCount{Domain: k, Count: v}
	})

	// Sending pattern
	if err := d.QueryRow(`
		SELECT CAST(COUNT(*) AS REAL) / MAX(1, JULIANDAY('now') - JULIANDAY(MIN(date)))
		FROM emails WHERE class = 'outbound'`).Scan(&ctx.SendingPattern.AvgPerDay); err != nil {
		return nil, fmt.Errorf("querying avg sends per day: %w", err)
	}
	ctx.SendingPattern.AvgPerWeek = ctx.SendingPattern.AvgPerDay * 7

	if err := d.QueryRow(`
		SELECT CASE CAST(strftime('%w', date) AS INTEGER)
			WHEN 0 THEN 'Sunday' WHEN 1 THEN 'Monday' WHEN 2 THEN 'Tuesday'
			WHEN 3 THEN 'Wednesday' WHEN 4 THEN 'Thursday' WHEN 5 THEN 'Friday'
			WHEN 6 THEN 'Saturday' END
		FROM emails WHERE class = 'outbound'
		GROUP BY strftime('%w', date) ORDER BY COUNT(*) DESC LIMIT 1`).Scan(&ctx.SendingPattern.MostActiveDay); err != nil {
		return nil, fmt.Errorf("querying most active day: %w", err)
	}

	// Recent outbound subjects
	subRows, err := d.Query("SELECT subject FROM emails WHERE class = 'outbound' ORDER BY date DESC LIMIT 50")
	if err != nil {
		return nil, fmt.Errorf("querying outbound subjects: %w", err)
	}
	defer subRows.Close()
	for subRows.Next() {
		var subj string
		if err := subRows.Scan(&subj); err != nil {
			return nil, fmt.Errorf("scanning subject row: %w", err)
		}
		ctx.CommonSubjects = append(ctx.CommonSubjects, subj)
	}
	if err := subRows.Err(); err != nil {
		return nil, fmt.Errorf("iterating subject rows: %w", err)
	}

	return ctx, nil
}

func topN[T any](counts map[string]int, n int, conv func(string, int) T) []T {
	type kv struct {
		k string
		v int
	}
	sorted := make([]kv, 0, len(counts))
	for k, v := range counts {
		sorted = append(sorted, kv{k, v})
	}
	sort.Slice(sorted, func(i, j int) bool {
		return sorted[i].v > sorted[j].v
	})
	if len(sorted) > n {
		sorted = sorted[:n]
	}
	result := make([]T, len(sorted))
	for i, s := range sorted {
		result[i] = conv(s.k, s.v)
	}
	return result
}

