package email

import (
	"database/sql"
	"fmt"
)

// CompactEmail has only the fields needed for classification — 4 fields instead of 11.
type CompactEmail struct {
	ID      string `json:"id"`
	Subject string `json:"subject"`
	From    string `json:"from"`
