package email

import (
	"database/sql"
	"fmt"
	"regexp"
	"strings"
	"time"

	gm "google.golang.org/api/gmail/v1"

	"github.com/usenurge/nurgesh/internal/sequence"
)

type ReplySyncResult struct {
	ThreadsScanned  int `json:"threads_scanned"`
	MessagesScanned int `json:"messages_scanned"`
	RepliesRecorded int `json:"replies_recorded"`
	Paused          int `json:"paused"`
	Stopped         int `json:"stopped"`
}

func SyncReplies(srv *gm.Service, d *sql.DB, mailboxEmail string, now time.Time) (*ReplySyncResult, error) {
	if now.IsZero() {
		now = time.Now()
	}

	enrollments, err := sequence.ListEnrollments(d, sequence.StatusActive, 0)
	if err != nil {
		return nil, err
	}

	result := &ReplySyncResult{}
	for _, enrollment := range enrollments {
		if enrollment.ThreadID == "" {
			fmt.Printf("  warning: enrollment %s has no ThreadID, skipping\n", enrollment.ID)
			continue
		}
		if mailboxEmail != "" && !strings.EqualFold(mailboxEmail, enrollment.MailboxEmail) {
			continue
		}

		ctx, cancel := apiCtx()
		thread, err := srv.Users.Threads.Get("me", enrollment.ThreadID).Format("metadata").
			MetadataHeaders("Subject", "From", "To", "Cc", "Date").Context(ctx).Do()
		cancel()
		if err != nil {
			return nil, err
		}
		result.ThreadsScanned++

		watermark := latestKnownThreadTime(enrollment)
		for i := 0; i < len(thread.Messages); i++ {
			result.MessagesScanned++
			raw := parseMessage(thread.Messages[i])
			raw.Direction = inferDirection(raw, enrollment.MailboxEmail)
			if raw.Direction != "inbound" {
				continue
			}
			if mailboxEmail != "" && strings.EqualFold(strings.TrimSpace(raw.FromEmail), strings.TrimSpace(mailboxEmail)) {
				continue
			}

			occurredAt, ok := parseStoredEmailTime(raw.Date)
			if !ok {
				continue
			}
			if !watermark.IsZero() && occurredAt.Before(watermark) {
				continue
			}

			raw.ThreadID = enrollment.ThreadID
			raw.Direction = "inbound"
			if err := StoreEmail(d, raw); err != nil {
				return nil, err
			}

			reply, err := sequence.RecordReply(d, sequence.ReplyOptions{
				EnrollmentID:   enrollment.ID,
				MailboxID:      enrollment.MailboxID,
				ThreadID:       enrollment.ThreadID,
				MessageID:      raw.ID,
				ContactEmail:   raw.FromEmail,
				Classification: classifyReply(raw.FromEmail, raw.Subject, raw.Snippet),
				Subject:        raw.Subject,
				Snippet:        raw.Snippet,
				OccurredAt:     occurredAt,
			})
			if err != nil {
				return nil, err
			}

			result.RepliesRecorded++
			if reply.Classification == "not_interested" || reply.Classification == "unsubscribe" || reply.Classification == "bounced" {
				result.Stopped++
			} else {
				result.Paused++
			}
		}
	}

	return result, nil
}

func classifyReply(fromEmail, subject, snippet string) string {
	text := strings.ToLower(strings.TrimSpace(fromEmail) + "\n" + subject + "\n" + snippet)
	switch {
	case containsAny(text, "mailer-daemon", "postmaster", "delivery status notification", "undeliverable", "message blocked", "delivery has failed"):
		return "bounced"
	case containsAny(text, "out of office", "out-of-office", "automatic reply", "auto-reply", "away until") || containsWord(text, "ooo"):
		return "out_of_office"
	case containsAny(text, "unsubscribe", "stop emailing", "do not contact"):
		return "unsubscribe"
	case containsAny(text, "not interested", "no interest", "no thanks", "remove me"):
		return "not_interested"
	case containsWord(text, "yes") || containsAny(text, "interested", "sounds good", "let's chat", "let us chat", "worth a look", "happy to talk"):
		return "interested"
	case containsAny(text, "reach out to", "talk to", "speak with", "contact ") && strings.Contains(text, "@"):
		return "referral"
	default:
		return "replied"
	}
}

func containsWord(text, word string) bool {
	re := regexp.MustCompile(`\b` + regexp.QuoteMeta(word) + `\b`)
	return re.MatchString(text)
}

func latestKnownThreadTime(enrollment sequence.Enrollment) time.Time {
	candidates := []string{enrollment.LastReplyAt, enrollment.LastSentAt}
	for _, candidate := range candidates {
		if candidate == "" {
			continue
		}
		if ts, err := time.Parse(time.RFC3339, candidate); err == nil {
			return ts.UTC()
		}
	}
	return time.Time{}
}

func inferDirection(message *RawMessage, mailboxEmail string) string {
	if mailboxEmail != "" && strings.EqualFold(strings.TrimSpace(message.FromEmail), strings.TrimSpace(mailboxEmail)) {
		return "outbound"
	}
	return "inbound"
}

func containsAny(text string, needles ...string) bool {
	for _, needle := range needles {
		if strings.Contains(text, needle) {
			return true
		}
	}
	return false
}

