package session

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"strings"
)

// DistillResult summarizes the outcome of distilling raw learnings into
// knowledge atom updates and strategic memory entries.
type DistillResult struct {
	LearningsProcessed int      `json:"learnings_processed"`
	AtomsUpdated       int      `json:"atoms_updated"`
	AtomsCreated       int      `json:"atoms_created"`
	Categories         []string `json:"categories"`
}

// learningTypeToAtomTypes maps learning types to the knowledge atom types they
// should be appended to.
var learningTypeToAtomTypes = map[string][]string{
	"tone":       {"tone"},
	"icp":        {"personas", "positioning"},
	"product":    {"positioning"},
	"pattern":    {"hooks", "tone"},
	"preference": {}, // preferences are context-dependent; handled specially
}

// Distill processes undistilled learnings, appending them to the relevant
// knowledge atoms and strategic memory entries, then marks them as distilled.
//
// The operation is mechanical: learning content is appended to a "learnings"
// array inside each matching atom's JSON content. This preserves the original
// atom content while accumulating session insights.
func Distill(db *sql.DB) (*DistillResult, error) {
	result := &DistillResult{}

	// 1. Load undistilled learnings
	learnings, err := listUndistilledLearnings(db)
	if err != nil {
		return nil, fmt.Errorf("loading undistilled learnings: %w", err)
	}
	if len(learnings) == 0 {
		return result, nil
	}

	// 2. Group by type
	groups := map[string][]Learning{}
	for _, l := range learnings {
		groups[l.Type] = append(groups[l.Type], l)
	}

	// 3. Process each group
	categorySet := map[string]bool{}
	for typ, items := range groups {
		categorySet[typ] = true

		switch typ {
		case "competitor":
			// Competitors go to strategic memory
			for _, l := range items {
				if err := saveCompetitorMemory(db, l); err != nil {
					return nil, fmt.Errorf("saving competitor memory: %w", err)
				}
			}

		case "preference":
			// Preferences: try to match to relevant atom types based on content keywords
			for _, l := range items {
				atomTypes := inferAtomTypesFromPreference(l.Content)
				for _, atomType := range atomTypes {
					created, err := appendLearningToAtoms(db, atomType, l)
					if err != nil {
						return nil, fmt.Errorf("appending preference to %s atoms: %w", atomType, err)
					}
					if created {
						result.AtomsCreated++
					} else {
						result.AtomsUpdated++
					}
				}
			}

		default:
			// Standard mapping: tone, icp, product, pattern
			atomTypes, ok := learningTypeToAtomTypes[typ]
			if !ok {
				// Unknown learning type -- log a warning and skip, but still mark as distilled
				log.Printf("[distill] warning: unknown learning type %q with %d items, skipping atom updates", typ, len(items))
				continue
			}
			for _, atomType := range atomTypes {
				for _, l := range items {
					created, err := appendLearningToAtoms(db, atomType, l)
					if err != nil {
						return nil, fmt.Errorf("appending %s learning to %s atoms: %w", typ, atomType, err)
					}
					if created {
						result.AtomsCreated++
					} else {
						result.AtomsUpdated++
					}
				}
			}
		}
	}

	// 4. Mark all as distilled.
	// We mark after processing each group above, but also do a final
	// batch mark to catch any that were skipped (e.g. unknown types).
	ids := make([]int, len(learnings))
	for i, l := range learnings {
		ids[i] = l.ID
	}
	if err := markDistilled(db, ids); err != nil {
		return nil, fmt.Errorf("marking learnings as distilled: %w", err)
	}

	result.LearningsProcessed = len(learnings)
	for cat := range categorySet {
		result.Categories = append(result.Categories, cat)
	}

	return result, nil
}

// listUndistilledLearnings returns learnings that have not yet been distilled.
func listUndistilledLearnings(db *sql.DB) ([]Learning, error) {
	rows, err := db.Query(`
		SELECT id, type, content, source_session, created_at
		FROM learnings
		WHERE distilled_at IS NULL OR distilled_at = ''
		ORDER BY created_at ASC`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var learnings []Learning
	for rows.Next() {
		var l Learning
		if err := rows.Scan(&l.ID, &l.Type, &l.Content, &l.SourceSession, &l.CreatedAt); err != nil {
			return nil, err
		}
		learnings = append(learnings, l)
	}
	return learnings, rows.Err()
}

// markDistilled sets the distilled_at timestamp for the given learning IDs.
func markDistilled(db *sql.DB, ids []int) error {
	if len(ids) == 0 {
		return nil
	}

	// Build batch update with placeholders
	placeholders := make([]string, len(ids))
	args := make([]any, len(ids))
	for i, id := range ids {
		placeholders[i] = "?"
		args[i] = id
	}

	query := fmt.Sprintf(
		"UPDATE learnings SET distilled_at = datetime('now'), updated_at = datetime('now') WHERE id IN (%s)",
		strings.Join(placeholders, ","),
	)
	_, err := db.Exec(query, args...)
	return err
}

// appendLearningToAtoms finds atoms of the given type and appends the learning
// content to a "learnings" array in each atom's JSON content.
//
// If no atoms of the type exist, one is created with the global (empty) scope.
// Returns true if a new atom was created.
func appendLearningToAtoms(db *sql.DB, atomType string, learning Learning) (bool, error) {
	// Find existing atoms of this type
	rows, err := db.Query(
		`SELECT id, content FROM knowledge_atoms WHERE atom_type = ?`,
		atomType,
	)
	if err != nil {
		return false, err
	}
	defer rows.Close()

	var found bool
	for rows.Next() {
		found = true
		var id int
		var content string
		if err := rows.Scan(&id, &content); err != nil {
			return false, err
		}

		updated, err := appendLearningToJSON(content, learning)
		if err != nil {
			return false, err
		}

		_, err = db.Exec(
			`UPDATE knowledge_atoms SET content = ?, updated_at = datetime('now') WHERE id = ?`,
			updated, id,
		)
		if err != nil {
			return false, fmt.Errorf("updating atom %d: %w", id, err)
		}
	}
	if err := rows.Err(); err != nil {
		return false, err
	}

	if found {
		return false, nil
	}

	// No atoms of this type exist — create a new one with global scope
	initial := map[string]any{
		"learnings": []map[string]string{
			{
				"type":       learning.Type,
				"content":    learning.Content,
				"created_at": learning.CreatedAt,
			},
		},
	}
	initialJSON, err := json.Marshal(initial)
	if err != nil {
		return false, err
	}

	_, err = db.Exec(
		`INSERT INTO knowledge_atoms (atom_type, scope, content, source, confidence) VALUES (?, '', ?, 'distill', 0.8)`,
		atomType, string(initialJSON),
	)
	if err != nil {
		return false, fmt.Errorf("creating atom for type %s: %w", atomType, err)
	}
	return true, nil
}

// appendLearningToJSON takes existing atom JSON content and appends a learning
// entry to the "learnings" array within it.
func appendLearningToJSON(existingContent string, learning Learning) (string, error) {
	var data map[string]any
	if err := json.Unmarshal([]byte(existingContent), &data); err != nil {
		// If existing content isn't a JSON object, wrap it
		data = map[string]any{
			"original": existingContent,
		}
	}

	// Get or create the learnings array
	var learnings []any
	if existing, ok := data["learnings"]; ok {
		if arr, ok := existing.([]any); ok {
			learnings = arr
		}
	}

	// Append the new learning
	learnings = append(learnings, map[string]string{
		"type":       learning.Type,
		"content":    learning.Content,
		"created_at": learning.CreatedAt,
	})
	data["learnings"] = learnings

	result, err := json.Marshal(data)
	if err != nil {
		return "", err
	}
	return string(result), nil
}

// saveCompetitorMemory stores a competitor learning as strategic memory.
func saveCompetitorMemory(db *sql.DB, learning Learning) error {
	return SaveStrategicMemory(db, StrategicMemoryInput{
		Category:       "competitor_intel",
		Summary:        learning.Content,
		AffectedSkills: []string{"nurge-outbound", "nurge-research", "nurge-qualify"},
		Source:         "learning_distill",
		SourceKey:      fmt.Sprintf("competitor_learning_%d", learning.ID),
		Priority:       1,
	})
}

// inferAtomTypesFromPreference guesses which atom types a preference learning
// should be appended to, based on content keywords.
func inferAtomTypesFromPreference(content string) []string {
	lower := strings.ToLower(content)
	var types []string

	if strings.Contains(lower, "tone") || strings.Contains(lower, "voice") || strings.Contains(lower, "casual") || strings.Contains(lower, "formal") || strings.Contains(lower, "salesy") {
		types = append(types, "tone")
	}
	if strings.Contains(lower, "subject") || strings.Contains(lower, "hook") || strings.Contains(lower, "opening") {
		types = append(types, "hooks")
	}
	if strings.Contains(lower, "structure") || strings.Contains(lower, "format") || strings.Contains(lower, "length") || strings.Contains(lower, "short") || strings.Contains(lower, "long") {
		types = append(types, "tone")
	}
	if strings.Contains(lower, "position") || strings.Contains(lower, "product") || strings.Contains(lower, "pricing") || strings.Contains(lower, "value") {
		types = append(types, "positioning")
	}
	if strings.Contains(lower, "persona") || strings.Contains(lower, "icp") || strings.Contains(lower, "target") || strings.Contains(lower, "audience") {
		types = append(types, "personas")
	}

	// If no match, default to tone (most common preference type)
	if len(types) == 0 {
		types = append(types, "tone")
	}
	return types
}

