// convex/slack.ts
//
// Slack notification and interactive message handling for reply drafts.
// Sends draft previews with approve/edit/skip buttons.
// Handles callbacks to send approved replies via existing Unipile path.
//
// Hardened: signature verification, error tracking, auto-revoke,
// lastUsedAt updates, Slack message updates on send result.

import { v } from "convex/values";
import {
  internalAction,
  internalMutation,
  internalQuery,
  httpAction,
} from "./_generated/server";
import type { ActionCtx } from "./_generated/server";
import { internal } from "./_generated/api";
import { decryptToken } from "./crypto";
import { callGmailSend, getAccessTokenForUser } from "./gmailApi";
import { callUnipileSend } from "./send";
import { Id } from "./_generated/dataModel";

const SLACK_API = "https://slack.com/api";
const MAX_CONSECUTIVE_ERRORS = 5;

// ── Signature verification ──────────────────────────────────────────

async function verifySlackSignature(
  request: Request,
  rawBody: string
): Promise<boolean> {
  const signingSecret = process.env.SLACK_SIGNING_SECRET;
  if (!signingSecret) {
    console.warn("SLACK_SIGNING_SECRET not set - skipping signature verification");
    return true; // Degrade gracefully in dev
  }

  const timestamp = request.headers.get("X-Slack-Request-Timestamp");
  const signature = request.headers.get("X-Slack-Signature");

  if (!timestamp || !signature) return false;

  // Reject requests older than 5 minutes (replay attack prevention)
  const now = Math.floor(Date.now() / 1000);
  if (Math.abs(now - parseInt(timestamp)) > 300) return false;

  const sigBasestring = `v0:${timestamp}:${rawBody}`;
  const key = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(signingSecret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );

  const signed = await crypto.subtle.sign(
    "HMAC",
    key,
    new TextEncoder().encode(sigBasestring)
  );

  const computed = "v0=" + Array.from(new Uint8Array(signed))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");

  return computed === signature;
}

// ── Helper: call Slack API with error tracking ──────────────────────

async function slackApiCall(
  ctx: ActionCtx,
  botToken: string,
  method: string,
  body: Record<string, unknown>,
  userId: string
): Promise<{ ok: boolean; data: any; error?: string }> {
  const resp = await fetch(`${SLACK_API}/${method}`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${botToken}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(body),
  });

  const data = await resp.json();

  if (data.ok) {
    // Reset error tracking on success
    await ctx.runMutation(internal.slack.trackSlackSuccess, { userId });
    return { ok: true, data };
  }

  // Track the error
  await ctx.runMutation(internal.slack.trackSlackError, {
    userId,
    error: data.error || `HTTP ${resp.status}`,
  });

  // Token revoked by user in Slack settings
  if (data.error === "token_revoked" || data.error === "invalid_auth") {
    await ctx.runMutation(internal.slack.revokeSlackConnection, {
      userId,
    });
  }

  return { ok: false, data, error: data.error };
}

// ── Helper: get bot token for a user ────────────────────────────────

async function getBotToken(
  ctx: ActionCtx,
  userId: string
): Promise<{ token: string; conn: any } | null> {
  const conn = await ctx.runQuery(internal.slack.getSlackConnection, {
    userId,
  });
  if (!conn || conn.status !== "active") return null;

  try {
    const token = await decryptToken(conn.encryptedBotToken, conn.botTokenIv);
    return { token, conn };
  } catch (e: unknown) {
    const message = e instanceof Error ? e.message : String(e);
    console.error("Failed to decrypt Slack bot token:", message);
    return null;
  }
}

// ── Send Slack notification for a draft ─────────────────────────────

export const notifyDraft = internalAction({
  args: { draftId: v.id("replyDrafts") },
  handler: async (ctx, args) => {
    const draft = await ctx.runQuery(internal.slack.getDraft, {
      draftId: args.draftId,
    });
    if (!draft || draft.status !== "pending_review") return;

    const auth = await getBotToken(ctx, draft.userId);
    if (!auth) return;

    const classificationLabel: Record<string, string> = {
      interested: "INTERESTED",
      replied: "REPLY",
      referral: "REFERRAL",
      out_of_office: "OOO",
    };

    const label =
      classificationLabel[draft.classification] ||
      draft.classification.toUpperCase();
    const wordCount = (draft.draftBody || "").split(/\s+/).length;

    const blocks = [
      {
        type: "header",
        text: {
          type: "plain_text",
          text: `Reply from ${draft.contactName || draft.contactEmail}`,
        },
      },
      {
        type: "section",
        text: {
          type: "mrkdwn",
          text: `*${label}*  |  ${draft.originalSubject}\n\n> ${draft.originalSnippet}`,
        },
      },
      { type: "divider" },
      {
        type: "section",
        text: {
          type: "mrkdwn",
          text: `*Draft reply* (${wordCount} words, confidence: ${draft.confidence || "medium"}):\n\n${draft.draftBody}`,
        },
      },
      {
        type: "actions",
        block_id: `reply_actions_${String(draft._id)}`,
        elements: [
          {
            type: "button",
            text: { type: "plain_text", text: "Send" },
            style: "primary",
            action_id: "approve_reply",
            value: String(draft._id),
          },
          {
            type: "button",
            text: { type: "plain_text", text: "Edit" },
            action_id: "edit_reply",
            value: String(draft._id),
          },
          {
            type: "button",
            text: { type: "plain_text", text: "Skip" },
            action_id: "skip_reply",
            value: String(draft._id),
          },
        ],
      },
    ];

    const result = await slackApiCall(
      ctx,
      auth.token,
      "chat.postMessage",
      {
        channel: auth.conn.channelId,
        blocks,
        text: `Reply from ${draft.contactEmail}: ${draft.originalSnippet}`,
      },
      draft.userId
    );

    if (result.ok && result.data.ts) {
      await ctx.runMutation(internal.slack.markNotified, {
        draftId: args.draftId,
        slackMessageTs: result.data.ts,
      });
    } else {
      console.error("Slack postMessage failed:", result.error);
    }
  },
});

// ── Update Slack message after action ────────────────────────────────

async function updateSlackMessage(
  ctx: ActionCtx,
  userId: string,
  channel: string,
  messageTs: string,
  text: string
) {
  const auth = await getBotToken(ctx, userId);
  if (!auth) return;

  await slackApiCall(ctx, auth.token, "chat.update", {
    channel,
    ts: messageTs,
    text,
    blocks: [], // Remove buttons
  }, userId);
}

// ── Slack interactive callback handler ──────────────────────────────

export const slackCallback = httpAction(async (ctx, request) => {
  // Read raw body for signature verification (must be done before parsing)
  const rawBody = await request.text();

  // Verify Slack signature
  const isValid = await verifySlackSignature(request, rawBody);
  if (!isValid) {
    console.error("Slack signature verification failed");
    return new Response("Invalid signature", { status: 401 });
  }

  // Parse the form data from raw body
  const params = new URLSearchParams(rawBody);
  const payloadStr = params.get("payload");
  if (!payloadStr) {
    return new Response("Missing payload", { status: 400 });
  }

  const payload = JSON.parse(payloadStr);

  // Handle view submissions (edit modal)
  if (payload.type === "view_submission") {
    const callbackId = payload.view?.callback_id || "";
    const draftIdStr = callbackId.replace("edit_reply_", "");
    const editedBody =
      payload.view?.state?.values?.reply_body?.body?.value || "";

    if (editedBody && draftIdStr) {
      const draftId = draftIdStr as Id<"replyDrafts">;
      const sendData = await ctx.runMutation(
        internal.replyDrafts.approveDraft,
        { draftId, editedBody }
      );

      if (sendData) {
        await sendApprovedReply(ctx, draftId, sendData);
      }
    }

    return new Response("", { status: 200 });
  }

  // Handle button actions
  const action = payload.actions?.[0];
  if (!action) {
    return new Response("No action", { status: 400 });
  }

  const draftId = action.value as Id<"replyDrafts">;

  // Get draft for context (needed for message update)
  const draft = await ctx.runQuery(internal.slack.getDraft, { draftId });

  if (action.action_id === "approve_reply") {
    const sendData = await ctx.runMutation(
      internal.replyDrafts.approveDraft,
      { draftId }
    );

    if (sendData) {
      const sent = await sendApprovedReply(ctx, draftId, sendData);

      // Update the Slack message to show result
      if (draft?.slackMessageTs) {
        const slackConn = await ctx.runQuery(
          internal.slack.getSlackConnection,
          { userId: draft.userId }
        );
        if (slackConn) {
          const statusText = sent
            ? `Reply sent to ${sendData.contactEmail}.`
            : `Failed to send reply to ${sendData.contactEmail}. Check email connection.`;
          await updateSlackMessage(
            ctx,
            draft.userId,
            slackConn.channelId,
            draft.slackMessageTs,
            statusText
          );
        }
      }
    }

    return new Response(
      JSON.stringify({
        replace_original: true,
        text: `Reply sent to ${sendData?.contactEmail || "contact"}.`,
      }),
      { status: 200, headers: { "Content-Type": "application/json" } }
    );
  }

  if (action.action_id === "skip_reply") {
    await ctx.runMutation(internal.replyDrafts.rejectDraft, { draftId });

    // Update Slack message
    if (draft?.slackMessageTs) {
      const slackConn = await ctx.runQuery(
        internal.slack.getSlackConnection,
        { userId: draft.userId }
      );
      if (slackConn) {
        await updateSlackMessage(
          ctx,
          draft.userId,
          slackConn.channelId,
          draft.slackMessageTs,
          `Reply to ${draft.contactEmail} skipped.`
        );
      }
    }

    return new Response(
      JSON.stringify({
        replace_original: true,
        text: "Reply skipped.",
      }),
      { status: 200, headers: { "Content-Type": "application/json" } }
    );
  }

  if (action.action_id === "edit_reply") {
    if (!draft) {
      return new Response("Draft not found", { status: 404 });
    }

    // Open modal via Slack views.open API
    const auth = await getBotToken(ctx, draft.userId);
    if (auth) {
      await slackApiCall(ctx, auth.token, "views.open", {
        trigger_id: payload.trigger_id,
        view: {
          type: "modal",
          callback_id: `edit_reply_${String(draftId)}`,
          title: { type: "plain_text", text: "Edit Reply" },
          submit: { type: "plain_text", text: "Send" },
          blocks: [
            {
              type: "input",
              block_id: "reply_body",
              element: {
                type: "plain_text_input",
                action_id: "body",
                multiline: true,
                initial_value: draft.draftBody || "",
              },
              label: { type: "plain_text", text: "Reply" },
            },
          ],
        },
      }, draft.userId);
    }

    return new Response("", { status: 200 });
  }

  return new Response("OK", { status: 200 });
});

// ── Send approved reply via existing Unipile path ───────────────────

async function sendApprovedReply(
  ctx: ActionCtx,
  draftId: Id<"replyDrafts">,
  sendData: {
    userId: string;
    contactEmail: string;
    threadId: string;
    subject: string;
    body: string;
  }
): Promise<boolean> {
  // Prefer direct Gmail API (no Unipile dependency, no cost)
  const gmailAuth = await getAccessTokenForUser(ctx, sendData.userId);
  if (gmailAuth) {
    const result = await callGmailSend({
      accessToken: gmailAuth.accessToken,
      from: gmailAuth.email,
      to: sendData.contactEmail,
      subject: sendData.subject,
      body: sendData.body,
      threadId: sendData.threadId,
    });

    if (result.ok) {
      await ctx.runMutation(internal.replyDrafts.markDraftSent, { draftId });
      return true;
    }

    // If Gmail auth error, fall through to Unipile
    if (!result.authError) {
      console.error("Gmail send failed:", result.error);
      return false;
    }
    console.warn("Gmail auth failed, falling back to Unipile");
  }

  // Fallback: Unipile (if Gmail credentials unavailable or auth expired)
  const unipileAccount = await ctx.runQuery(
    internal.sendApi.findUnipileAccount,
    { userId: sendData.userId, provider: "GOOGLE" }
  );

  if (!unipileAccount || unipileAccount.status !== "connected") {
    console.error("No send path available: Gmail credentials expired and Unipile not connected");
    return false;
  }

  const enrollment = await ctx.runQuery(
    internal.slack.findEnrollmentByThread,
    { userId: sendData.userId, threadId: sendData.threadId }
  );

  const sendResult = await callUnipileSend({
    accountId: unipileAccount.unipileAccountId,
    to: sendData.contactEmail,
    subject: sendData.subject,
    body: sendData.body,
    replyTo: enrollment?.unipileThreadProviderId || undefined,
  });

  if (sendResult.ok) {
    await ctx.runMutation(internal.replyDrafts.markDraftSent, { draftId });
    return true;
  }

  console.error("Unipile send failed:", sendResult.error);
  return false;
}

// ── Health check (called periodically or on demand) ─────────────────

export const healthCheck = internalAction({
  args: { userId: v.string() },
  handler: async (ctx, args) => {
    const auth = await getBotToken(ctx, args.userId);
    if (!auth) {
      return { healthy: false, error: "no_connection" };
    }

    const result = await slackApiCall(
      ctx,
      auth.token,
      "auth.test",
      {},
      args.userId
    );

    return {
      healthy: result.ok,
      team: result.data?.team,
      user: result.data?.user,
      error: result.error,
    };
  },
});

// ── Internal queries ────────────────────────────────────────────────

export const getDraft = internalQuery({
  args: { draftId: v.id("replyDrafts") },
  handler: async (ctx, args) => {
    return await ctx.db.get(args.draftId);
  },
});

export const getSlackConnection = internalQuery({
  args: { userId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("slackConnections")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
  },
});

export const findEnrollmentByThread = internalQuery({
  args: { userId: v.string(), threadId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_thread", (q) =>
        q.eq("userId", args.userId).eq("threadId", args.threadId)
      )
      .first();
  },
});

// ── Internal mutations ──────────────────────────────────────────────

export const upsertSlackConnection = internalMutation({
  args: {
    userId: v.string(),
    teamId: v.string(),
    teamName: v.optional(v.string()),
    channelId: v.string(),
    channelName: v.optional(v.string()),
    encryptedBotToken: v.string(),
    botTokenIv: v.string(),
    scopes: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("slackConnections")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .collect();

    const now = new Date().toISOString();
    const patch = {
      teamId: args.teamId,
      teamName: args.teamName,
      channelId: args.channelId,
      channelName: args.channelName,
      encryptedBotToken: args.encryptedBotToken,
      botTokenIv: args.botTokenIv,
      scopes: args.scopes,
      installedAt: now,
      lastUsedAt: now,
      lastErrorAt: undefined as string | undefined,
      lastError: undefined as string | undefined,
      consecutiveErrors: 0,
      status: "active",
    };

    if (existing.length === 0) {
      await ctx.db.insert("slackConnections", {
        userId: args.userId,
        ...patch,
      });
      return;
    }

    await ctx.db.patch(existing[0]._id, patch);
    // Revoke duplicates
    for (const duplicate of existing.slice(1)) {
      await ctx.db.patch(duplicate._id, { status: "revoked" });
    }
  },
});

export const revokeSlackConnection = internalMutation({
  args: { userId: v.string() },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("slackConnections")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .collect();

    const now = new Date().toISOString();
    for (const conn of existing) {
      await ctx.db.patch(conn._id, {
        status: "revoked",
        lastUsedAt: now,
      });
    }
  },
});

export const trackSlackSuccess = internalMutation({
  args: { userId: v.string() },
  handler: async (ctx, args) => {
    const conn = await ctx.db
      .query("slackConnections")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    if (!conn || conn.status !== "active") return;

    await ctx.db.patch(conn._id, {
      lastUsedAt: new Date().toISOString(),
      consecutiveErrors: 0,
    });
  },
});

export const trackSlackError = internalMutation({
  args: { userId: v.string(), error: v.string() },
  handler: async (ctx, args) => {
    const conn = await ctx.db
      .query("slackConnections")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    if (!conn) return;

    const errors = (conn.consecutiveErrors || 0) + 1;
    const now = new Date().toISOString();

    if (errors >= MAX_CONSECUTIVE_ERRORS) {
      // Auto-revoke after too many consecutive failures
      await ctx.db.patch(conn._id, {
        status: "error",
        lastErrorAt: now,
        lastError: `Auto-disabled after ${errors} consecutive errors: ${args.error}`,
        consecutiveErrors: errors,
        lastUsedAt: now,
      });
      console.error(
        `Slack connection auto-disabled for user ${args.userId} after ${errors} errors`
      );
    } else {
      await ctx.db.patch(conn._id, {
        lastErrorAt: now,
        lastError: args.error,
        consecutiveErrors: errors,
        lastUsedAt: now,
      });
    }
  },
});

export const markNotified = internalMutation({
  args: {
    draftId: v.id("replyDrafts"),
    slackMessageTs: v.string(),
  },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.draftId, {
      slackMessageTs: args.slackMessageTs,
      notifiedAt: new Date().toISOString(),
    });
  },
});

