  2→//
  3→// Receives deal stage change webhooks from HubSpot (and future CRMs).
  4→// Extracts won/lost outcome and computes attribution back to Nurge sequences.
  5→
  6→import { v } from "convex/values";
  7→import {
  8→  httpAction,
  9→  internalMutation,
 10→} from "./_generated/server";
 11→import { internal } from "./_generated/api";
 12→
 13→// ── HubSpot webhook handler ────────────────────────────────────────
 14→
 15→export const hubspotDealWebhook = httpAction(async (ctx, request) => {
 16→  const contentType = request.headers.get("content-type") || "";
 17→  if (!contentType.includes("application/json")) {
 18→    return new Response("Content-Type must be application/json", { status: 415 });
 19→  }
 20→
 21→  try {
 22→    const events = await request.json();
 23→
 24→    for (const event of events) {
 25→      if (
 26→        event.subscriptionType !== "deal.propertyChange" ||
 27→        event.propertyName !== "dealstage"
 28→      ) {
 29→        continue;
 30→      }
 31→
 32→      const dealId = String(event.objectId);
 33→      const newStage = event.propertyValue;
 34→
 35→      // Validate newStage is a non-empty string
 36→      if (!newStage || typeof newStage !== "string" || newStage.trim() === "") {
 37→        console.log(`Skipping deal ${dealId}: empty or invalid dealstage value`);
 38→        continue;
 39→      }
 40→
 41→      const outcome = mapHubSpotStage(newStage);
 42→      if (!outcome) continue;
