import { v } from "convex/values";
import { httpAction, internalMutation, internalQuery } from "./_generated/server";
import { internal } from "./_generated/api";

/**
 * Gmail Pub/Sub webhook handler.
 *
 * Gmail pushes notifications to a Google Cloud Pub/Sub topic, which forwards
 * them to this endpoint. The notification payload contains only the user's
 * email address and a historyId -- no email content ever flows through here.
 *
 * On receiving a notification, we mark the user as "needs sync" so the next
 * `nurge sync` call knows to pull changes via history.list.
 */
export const gmailPubSubWebhook = httpAction(async (ctx, request) => {
  const contentType = request.headers.get("content-type") || "";
  if (!contentType.includes("application/json")) {
    return new Response("Content-Type must be application/json", { status: 415 });
  }

  try {
    const payload = await request.json();

    // Pub/Sub wraps the data in a message envelope
    const message = payload.message;
    if (!message || !message.data) {
      return new Response("Missing message data", { status: 400 });
    }

    // Decode base64 payload: { emailAddress: string, historyId: number }
    let decoded: string;
    try {
      decoded = atob(message.data);
    } catch (decodeError) {
      console.error("Failed to decode base64 Pub/Sub data:", decodeError);
      // Return 200 to prevent Pub/Sub retry storms on permanently invalid data
      return new Response("OK", { status: 200 });
    }

    let data: any;
    try {
      data = JSON.parse(decoded);
    } catch (parseError) {
      console.error("Failed to parse Pub/Sub JSON data:", decoded);
      return new Response("OK", { status: 200 });
    }

    const emailAddress = data.emailAddress;
    const historyId = data.historyId !== undefined ? String(data.historyId) : "";

    // Validate required fields
    if (!emailAddress || typeof emailAddress !== "string") {
      console.error("Missing or invalid emailAddress in Pub/Sub notification:", JSON.stringify(data));
      return new Response("OK", { status: 200 });
    }
    if (!historyId) {
      console.error("Missing historyId in Pub/Sub notification:", JSON.stringify(data));
      return new Response("OK", { status: 200 });
    }

    await ctx.runMutation(internal.gmailWebhook.markPendingSync, {
      email: emailAddress,
      historyId,
    });

    // Trigger server-side reply fetch (runs as background action)
    await ctx.scheduler.runAfter(0, internal.gmailApi.fetchGmailReplies, {
      email: emailAddress,
      historyId,
    });

    // Always return 200 to acknowledge -- otherwise Pub/Sub retries
    return new Response("OK", { status: 200 });
  } catch (error: any) {
    console.error(
      "Gmail Pub/Sub webhook error processing notification:",
      error.message || error,
      error.stack
    );
    // Return 200 even on error to prevent Pub/Sub retry storms.
    // The notification will be picked up on the next polling sync.
    return new Response("OK", { status: 200 });
  }
});

/**
 * Mark a user's Gmail as needing sync after a Pub/Sub notification.
 */
export const markPendingSync = internalMutation({
  args: {
    email: v.string(),
    historyId: v.string(),
  },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("gmailWatchState")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, {
        historyId: args.historyId,
        pendingSync: true,
        lastNotifiedAt: new Date().toISOString(),
      });
    } else {
      // First notification for this email -- create the watch state.
      // The userId will be empty until the CLI registers via upsertWatchState.
      await ctx.db.insert("gmailWatchState", {
        userId: "",
        email: args.email,
        historyId: args.historyId,
        watchExpiry: "",
        pendingSync: true,
        lastNotifiedAt: new Date().toISOString(),
      });
    }
  },
});

/**
 * Register or update a Gmail watch state (called from CLI after users.watch()).
 */
export const upsertWatchState = internalMutation({
  args: {
    userId: v.string(),
    email: v.string(),
    historyId: v.string(),
    watchExpiry: v.string(),
  },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("gmailWatchState")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, {
        userId: args.userId,
        historyId: args.historyId,
        watchExpiry: args.watchExpiry,
        pendingSync: false,
      });
    } else {
      await ctx.db.insert("gmailWatchState", {
        userId: args.userId,
        email: args.email,
        historyId: args.historyId,
        watchExpiry: args.watchExpiry,
        pendingSync: false,
      });
    }
  },
});

/**
 * Get pending sync state for a user (called from CLI during nurge sync).
 */
export const getPendingSync = internalQuery({
  args: { email: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("gmailWatchState")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();
  },
});

/**
 * Clear pending sync flag after CLI has processed the sync.
 */
export const clearPendingSync = internalMutation({
  args: { email: v.string() },
  handler: async (ctx, args) => {
    const existing = await ctx.db
      .query("gmailWatchState")
      .withIndex("by_email", (q) => q.eq("email", args.email))
      .first();

    if (existing) {
      await ctx.db.patch(existing._id, { pendingSync: false });
    }
  },
});

/**
 * List all watches that need renewal (expiry < now + 1 day buffer).
 */
export const listExpiringWatches = internalQuery({
  args: {},
  handler: async (ctx) => {
    const all = await ctx.db.query("gmailWatchState").collect();
    const oneDayFromNow = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
    return all.filter(
      (w) => w.watchExpiry && w.watchExpiry < oneDayFromNow && w.userId !== ""
    );
  },
});

